import { useMemo } from 'react';
import { getLocalTimeZone, today } from '@internationalized/date';
import { useControlledState } from '@react-stately/utils';
import { Calendar as CalendarIcon } from '@untitledui/icons';
import { useDateFormatter } from 'react-aria';
import type {
  DatePickerProps as AriaDatePickerProps,
  DateValue,
} from 'react-aria-components';
import {
  DatePicker as AriaDatePicker,
  Dialog as AriaDialog,
  Group as AriaGroup,
  Popover as AriaPopover,
} from 'react-aria-components';
import { Button } from '@/components/atoms/Button';
import { cx } from '@/utils/cx';
import { Calendar } from '@/vendor/untitled-ui/application/date-picker/calendar';
import { WithDataId } from '@/types/withDataId';
import { DEFAULT_TEXTS } from './defaultTexts';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

export type DatePickerTexts = Pick<
  typeof DEFAULT_TEXTS,
  'placeholder' | 'cancelBtn' | 'applyBtn'
>;

const sizeStyles = {
  full: 'w-full justify-start',
};

export interface DatePickerProps
  extends
    AriaDatePickerProps<DateValue>,
    Omit<FieldWrapperProps, 'children'>,
    WithDataId {
  /** Custom formatter for displaying the selected date in the trigger button. */
  formatDate?: (date: Date) => string;
  /** The function to call when the apply button is clicked. */
  onApply?: () => void;
  /** The function to call when the cancel button is clicked. */
  onCancel?: () => void;
  /** Override default UI texts for i18n. */
  t?: DatePickerTexts;
  /** Override the default local timezone. */
  timeZone?: string;

  /** @deprecated Use fieldSize instead */
  size?: 'full';
}

export const DatePicker = ({
  value: valueProp,
  defaultValue,
  onChange,
  onApply,
  onCancel,
  formatDate,
  t: textsProp,
  timeZone,
  label,
  hint,
  isRequired = false,
  isInvalid = false,
  'data-id': dataId,
  fieldSize = 'auto',
  size,
  labelPosition = 'left',
  tooltip,
  description,
  id,
  ...props
}: DatePickerProps) => {
  const texts = textsProp ?? DEFAULT_TEXTS;
  const tz = timeZone ?? getLocalTimeZone();
  const formatter = useDateFormatter({
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
  const [value, setValue] = useControlledState(
    valueProp,
    defaultValue || null,
    onChange,
  );

  const highlightedDates = useMemo(() => [today(tz)], [tz]);

  const formatDisplayDate = (date: DateValue) => {
    const jsDate = date.toDate(tz);
    return formatDate ? formatDate(jsDate) : formatter.format(jsDate);
  };

  const formattedDate = value ? formatDisplayDate(value) : texts.placeholder;

  return (
    <FieldWrapper
      isRequired={isRequired}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
      tooltip={tooltip}
      description={description}
      id={id}
    >
      <AriaDatePicker
        shouldCloseOnSelect={false}
        {...props}
        value={value}
        onChange={setValue}
      >
        <AriaGroup>
          <Button
            size="sm"
            color="secondary"
            className={cx(
              isInvalid && 'ring-error_subtle',
              (fieldSize === 'full' || size === 'full') && sizeStyles.full,
            )}
            iconLeading={CalendarIcon}
            data-id={`${dataId}-calendar-icon-button`}
          >
            {formattedDate}
          </Button>
        </AriaGroup>
        <AriaPopover
          offset={8}
          placement="bottom right"
          className={({ isEntering, isExiting }) =>
            cx(
              'will-change-transform',
              isEntering &&
                'duration-150 ease-out animate-in fade-in placement-right:origin-left placement-right:slide-in-from-left-0.5 placement-top:origin-bottom placement-top:slide-in-from-bottom-0.5 placement-bottom:origin-top placement-bottom:slide-in-from-top-0.5',
              isExiting &&
                'duration-100 ease-in animate-out fade-out placement-right:origin-left placement-right:slide-out-to-left-0.5 placement-top:origin-bottom placement-top:slide-out-to-bottom-0.5 placement-bottom:origin-top placement-bottom:slide-out-to-top-0.5',
            )
          }
        >
          <AriaDialog className="rounded-2xl bg-primary shadow-xl ring ring-secondary_alt">
            {({ close }) => (
              <>
                <div className="flex px-6 py-5">
                  <Calendar
                    highlightedDates={highlightedDates}
                    data-id={`${dataId}-calendar`}
                  />
                </div>
                <div className="grid grid-cols-2 gap-3 border-t border-secondary p-4">
                  <Button
                    size="sm"
                    color="secondary"
                    onClick={() => {
                      onCancel?.();
                      close();
                    }}
                    data-id={`${dataId}-cancel-button`}
                  >
                    {texts.cancelBtn}
                  </Button>
                  <Button
                    size="sm"
                    color="primary"
                    onClick={() => {
                      onApply?.();
                      close();
                    }}
                    data-id={`${dataId}-apply-button`}
                  >
                    {texts.applyBtn}
                  </Button>
                </div>
              </>
            )}
          </AriaDialog>
        </AriaPopover>
      </AriaDatePicker>
    </FieldWrapper>
  );
};
